import { Avatar, Image } from 'antd';
import { UserOutlined } from '@ant-design/icons';
const MyAvatar = (text) => {
  let avatar_src = 'https://avatars.githubusercontent.com/u/' + text + '?v=4';
  return (
    <Avatar
      src={
        <Image
          src={avatar_src}
          fallback="data:image/png;base64,"
        />
      }
      size={32}
      icon={<UserOutlined />}
    />
  );
};
export default MyAvatar;
